              totalCost: { type: Type.NUMBER },
              marginPercentage: { type: Type.NUMBER },
              suggestedPrice: { type: Type.NUMBER }
            }
          },
          miseEnPlace: { type: Type.ARRAY, items: { type: Type.STRING } },
