          : (err.message || "No pudimos procesar tu solicitud. Intenta con un nombre de plato diferente."),
        type: isOverload ? 'overload' : 'generic'
      });
    } finally {
      setLoading(false);
    }
  };

  const handleExportPDF = async () => {
    const element = document.getElementById('printable-area');
    if (!element || !sheet) return;
    setExporting(true);
    try {
      const opt = {
        margin: [10, 10, 10, 10],
